  ('locality-814ced5a-moex-00326', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '下列題辭，最適合用在祝賀書店開張的是：', '["大筆如椽", "澤被桑梓", "聲重士林", "名山事業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00327', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '老師以「今之欲王者，猶七年之病，求三年之艾也」（《孟子‧離婁上》）警惕學生，下列選項，何者最 接近欲傳達的意旨？', '["懲忿窒欲", "思不出其位", "思患而豫防之", "多識前言往行以畜其德"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00328', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '《史記》中司馬遷評論郭解：「吾視郭解，狀貌不及中人，言語不足採者。然天下無賢與不肖，知與不 知，皆慕其聲，言俠者皆引以為名。諺曰：『人貌榮名，豈有既乎！』於戲，惜哉！」 根據上文，下列何者最合乎旨意？', '["長惡不悛，從自及也", "言行相詭，不祥莫大焉", "人不可貌相，海水不可斗量", "貌合心離者孤，親讒遠忠者亡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00329', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '《清史稿・趙廷臣列傳》有一段趙廷臣斷案的記載：「有瞽者入屠者室，攫其簝（裝肉的竹籃）中錢， 屠者逐之，則曰：『欺吾瞽，奪吾錢。』廷臣令投錢水中，見浮脂，以錢還屠者。」下列敘述，何者正 確？', '["關鍵證物是屠夫的竹籃", "真相釐清的關鍵是水上的油脂", "趙廷臣不具有證物鑑識的意識", "此案乃一盲人被控搶奪屠夫錢財"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00330', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「酒香不怕巷子深」，涵義與下列選項相去最遠的是：', '["心遠地自偏", "花香蝶自來", "梧高鳳必至", "功到自然成"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00331', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '江南中主時，有北苑使董源善畫，尤工秋嵐遠景，多寫江南真山，不為奇峭之筆。其後建業僧巨然祖 述源法，皆臻妙理。大體源及巨然畫筆，皆宜遠觀。其用筆甚草草，近視之幾不類物象；遠觀則景物 粲然，幽情遠思，如覩異境。如源畫落照圖，近視無功；遠觀村落杳然深遠，悉是晚景，遠峯之頂， 宛有反照之色，此妙處也。（沈括《夢溪筆談》） 根據上文所述，下列選項何者錯誤？', '["巨然畫風承繼董源而來", "巨然畫作適合從遠處觀賞", "董源擅長畫遠景，近觀亦臻精妙", "觀董源落照圖，遠觀則若有夕陽返照之色"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00332', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '宋代邵雍〈□□長吟〉，其部分詩句為：「搜羅神鬼聚胸臆，措置山河入範圍。局合龍蛇成陣鬥，劫殘 鴻雁破行飛；殺多項羽坑秦卒，敗劇苻堅畏晉師。座上戈鋌嘗擊搏，面前冰炭旋更移；死生共抵兩家 事，勝負都由一著時。」□□內應填入：', '["觀棋", "觀劍", "比武", "鬥雞"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00333', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '（豫）讓既自謂智伯待以國士矣，國士，濟國之事也，當伯請地無厭之日，縱欲荒棄之時，為讓者，正 宜陳力就列，諄諄然而告之……諄切懇告，諫不從；再諫之；再諫不從，三諫之，三諫不從，移其伏 劍之死，死於是日。伯雖頑冥不靈，感其至誠，庶幾復悟。和韓、魏，釋趙圍，保全智宗，守其祭祀。 若然，則讓雖死猶生也，豈不勝於斬衣而死乎？讓於此時，曾無一語開悟主心，視伯之危亡，猶越人 視秦人之肥瘠也。袖手旁觀，坐待成敗，國士之報，曾若是乎？智伯既死，而乃不勝血氣之悻悻，甘 自附於刺客之流。何足道哉？（方孝孺〈豫讓論〉） 本文為一翻案文章，作者駁斥豫讓「國士之報」的說法，是認為豫讓未能：', '["極力勸諫智伯", "和韓、魏，釋趙圍", "保全智宗，守其祭祀", "殺趙襄子替智伯報仇"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00334', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '承上題，「猶越人視秦人之肥瘠」的意思是：', '["人瘠己肥", "己瘠人肥", "事不關己", "己飢己溺"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00335', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '以下是一封寫給父親的信，□□中所用的「結尾問候語」及「署名敬辭」，完全正確的選項是： 父親大人尊前：叩別慈顏，瞬已匝月。我在軍中一切安好，遙請寬念！肅此 敬請□□ 男○○□□', '["金安、肅稟", "金安、敬啟", "福安、頓首", "福安、謹稟 時安、敬叩"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
